    if p.len() != 2 || start >= len || len > s.len() {
        return None;
    }
    let open = p[0];
    let close = p[1];
    let bytes = s.as_bytes();
    let mut depth = 1i32;
    let mut i = start + 1;
    while i < len {
        match bytes[i] {
            b'\\' => {
                i += 1;
            }
            b'\'' | b'"' => {
                let quote = bytes[i];
                i += 1;
                while i < len {
                    if bytes[i] == b'\\' {
                        i += 2;
                        continue;
                    }
                    if bytes[i] == quote {
                        break;
                    }
                    i += 1;
                }
            }
            c if c == open => depth += 1,
            c if c == close => {
                depth -= 1;
                if depth == 0 {
                    return Some(i);
                }
            }
            _ => {}
        }
        i += 1;
    }
    None
}

